import{c as t,Q as r,j as o,m as e}from"./chunks/framework.5k1Nei9d.js";const p=JSON.parse('{"title":"TrollStore 使用教程","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/ios-trollstore.md","filePath":"tutorials/ios-trollstore.md"}'),a={name:"tutorials/ios-trollstore.md"};function i(s,l,n,d,h,c){return r(),o("div",null,[...l[0]||(l[0]=[e('<h1 id="trollstore-使用教程" tabindex="-1">TrollStore 使用教程 <a class="header-anchor" href="#trollstore-使用教程" aria-label="Permalink to &quot;TrollStore 使用教程&quot;">​</a></h1><h2 id="什么是-trollstore" tabindex="-1">什么是 TrollStore？ <a class="header-anchor" href="#什么是-trollstore" aria-label="Permalink to &quot;什么是 TrollStore？&quot;">​</a></h2><p>TrollStore 是一个利用 <strong>CoreTrust 漏洞</strong> 实现永久签名的工具。通过它安装的应用不会过期，无需重新签名。</p><h2 id="支持范围" tabindex="-1">支持范围 <a class="header-anchor" href="#支持范围" aria-label="Permalink to &quot;支持范围&quot;">​</a></h2><ul><li><strong>iOS 14.0 - 16.6.1</strong>（部分版本需结合越狱）</li><li>安装方法因 iOS 版本不同而异</li></ul><h2 id="安装-trollstore" tabindex="-1">安装 TrollStore <a class="header-anchor" href="#安装-trollstore" aria-label="Permalink to &quot;安装 TrollStore&quot;">​</a></h2><h3 id="方法一-trollinstallerx-推荐" tabindex="-1">方法一：TrollInstallerX（推荐） <a class="header-anchor" href="#方法一-trollinstallerx-推荐" aria-label="Permalink to &quot;方法一：TrollInstallerX（推荐）&quot;">​</a></h3><ol><li>下载 <a href="https://github.com/alfiecg24/TrollInstallerX/releases" target="_blank" rel="noreferrer">TrollInstallerX</a></li><li>通过 AltStore / Sideloadly 签名安装到设备</li><li>打开 TrollInstallerX，点击 Install TrollStore</li><li>桌面出现 TrollStore 图标即成功</li></ol><h3 id="方法二-trollhelperota" tabindex="-1">方法二：TrollHelperOTA <a class="header-anchor" href="#方法二-trollhelperota" aria-label="Permalink to &quot;方法二：TrollHelperOTA&quot;">​</a></h3><ol><li>在 Safari 中访问安装页面</li><li>点击 Install TrollStore</li><li>等待安装完成</li></ol><div class="warning custom-block"><p class="custom-block-title">注意</p><p>安装方式因设备和 iOS 版本不同而有差异，请查阅最新信息确认适用方案。</p></div><h2 id="使用-trollstore-安装应用" tabindex="-1">使用 TrollStore 安装应用 <a class="header-anchor" href="#使用-trollstore-安装应用" aria-label="Permalink to &quot;使用 TrollStore 安装应用&quot;">​</a></h2><ol><li>下载 <code>.ipa</code> 或 <code>.tipa</code> 文件</li><li>点击分享按钮 → 选择「用 TrollStore 打开」</li><li>点击 Install 安装</li><li>桌面出现应用图标，<strong>永久有效</strong></li></ol><h2 id="推荐安装的应用" tabindex="-1">推荐安装的应用 <a class="header-anchor" href="#推荐安装的应用" aria-label="Permalink to &quot;推荐安装的应用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>应用</th><th>功能</th></tr></thead><tbody><tr><td><strong>Filza</strong></td><td>文件管理器</td></tr><tr><td><strong>AppStore++</strong></td><td>应用降级</td></tr><tr><td><strong>CocoaTop</strong></td><td>进程管理器</td></tr><tr><td><strong>Santander</strong></td><td>系统信息查看</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">提示</p><p>TrollStore 安装的应用具有与系统应用相同的权限，可以访问更多系统功能。</p></div>',16)])])}const u=t(a,[["render",i]]);export{p as __pageData,u as default};
